import java.math.BigInteger;
import java.util.List;

public class OrderValidator {
    // 订单总金额上限，单位：分
    private static final BigInteger TOTAL_AMOUNT_LIMIT = BigInteger.valueOf(100000000L);
    // 单商品数量上限
    private static final int QUANTITY_LIMIT = 1000;
    // 单商品单价上限，单位：分
    private static final long PRICE_LIMIT = 9999999L;

    public void validateOrder(List<GoodsItem> items) {
        // 校验入参：空订单（null或无商品）属于非法场景
        if (items == null || items.isEmpty()) {
            throw new IllegalOrderAmountException("订单为空，不合法");
        }

        // 使用BigInteger避免累加溢出，解决极端场景下的数值风险
        BigInteger totalAmount = BigInteger.ZERO;
        for (GoodsItem item : items) {
            int quantity = item.getQuantity();
            long price = item.getPrice();

            // 校验单商品购买数量：需>0且≤1000（覆盖边界值1000）
            if (quantity <= 0 || quantity > QUANTITY_LIMIT) {
                throw new IllegalGoodsQuantityException("商品数量不合法，需在1~1000之间");
            }
            // 校验单商品单价：需>0且≤9999999（覆盖边界值9999999）
            if (price <= 0 || price > PRICE_LIMIT) {
                throw new IllegalGoodsPriceException("商品单价不合法，需在1~9999999分之间");
            }

            // 计算当前商品总价，累加到订单总金额
            BigInteger itemAmount = BigInteger.valueOf(price).multiply(BigInteger.valueOf(quantity));
            totalAmount = totalAmount.add(itemAmount);

            // 校验订单总金额是否超过上限（覆盖边界值100000000）
            if (totalAmount.compareTo(TOTAL_AMOUNT_LIMIT) > 0) {
                throw new IllegalTotalAmountLimitException("订单总金额超过100万元上限");
            }
        }

        // 兜底校验总金额>0（前面校验通过后总金额必然>0，保留作为安全兜底）
        if (totalAmount.compareTo(BigInteger.ZERO) <= 0) {
            throw new IllegalOrderAmountException("订单总金额不合法");
        }
    }
}

// 商品项类
class GoodsItem {
    private long price; // 单位：分
    private int quantity; // 购买数量

    public GoodsItem(long price, int quantity) {
        this.price = price;
        this.quantity = quantity;
    }

    public long getPrice() { return price; }
    public void setPrice(long price) { this.price = price; }
    public int getQuantity() { return quantity; }
    public void setQuantity(int quantity) { this.quantity = quantity; }
}

// 定制异常类（按需求定义）
class IllegalOrderAmountException extends RuntimeException {
    public IllegalOrderAmountException(String message) { super(message); }
}
class IllegalGoodsQuantityException extends RuntimeException {
    public IllegalGoodsQuantityException(String message) { super(message); }
}
class IllegalGoodsPriceException extends RuntimeException {
    public IllegalGoodsPriceException(String message) { super(message); }
}
class IllegalTotalAmountLimitException extends RuntimeException {
    public IllegalTotalAmountLimitException(String message) { super(message); }
}
```
#### 修正说明：
1. 补充了商品数量、单价的下界校验（`<=0`），覆盖需求要求的非法场景；
2. 增加了入参`items`的非空校验，避免抛出非预期的NPE；
3. 使用`BigInteger`存储累加总金额，彻底消除极端场景下的溢出风险；
4. 所有边界值（1000件、9999999分、100000000分）均符合需求的合法要求，异常类型与需求完全匹配。

